                                write!(f, [space(), token("as"), space(), name.format()])?;
                            }
                        }
                        _ => {}
                    }

                    Ok(())
                }),
                dangling_comments,
                body,
                SuiteKind::other(self.last_suite_in_statement),
            )]
        )
    }
